-    match json {
-        Value::Object(map) => map.get(field),
-        Value::Array(arr) if !arr.is_empty() => {
-            // For arrays, check the first element
-            if let Value::Object(map) = &arr[0] {
-                map.get(field)
-            } else {
-                None
+    let mut current = json;
+    for part in field.split('.') {
+        match current {
+            Value::Object(map) => {
+                current = map.get(part)?;
+            }
+            Value::Array(arr) if !arr.is_empty() => {
+                if let Value::Object(map) = &arr[0] {
+                    current = map.get(part)?;
+                } else {
+                    return None;
+                }
             }
+            _ => return None,
         }
-        _ => None,
     }
+    Some(current)
